import React, { useEffect, useRef } from 'react';
import { Gradient } from './background.js';

function GradientCanvas() {
  const gradientRef = useRef(null);
  const gradient = useRef(null);

  useEffect(() => {
    // Check for GPU support
    const hasGPUSupport = window.navigator.gpu !== undefined;

    if (hasGPUSupport) {
      // Create the Gradient instance
      gradient.current = new Gradient();
      gradient.current.initGradient('#gradient-canvas');
    } else {
      // Handle case when GPU is not supported
      // Pause or disable the Gradient functionality
      // For example, you can call the pause method if it exists
      if (gradient.current && typeof gradient.current.pause === 'function') {
        gradient.current.pause();
      }
    }
  }, []);

  return <canvas id="gradient-canvas" ref={gradientRef} data-js-darken-top data-transition-in />;
}

export default GradientCanvas;
